INSERT INTO `system_notice` VALUES (1, '平台升级维护通知', '尊敬的商户：\n\n为了给您提供更好的服务，平台将于2026年1月26日凌晨2:00-6:00进行系统升级维护。\n\n维护期间，以下功能将暂时无法使用：\n1. 订单管理\n2. 财务结算\n3. 数据统计\n\n请您提前做好准备，给您带来的不便敬请谅解。\n\n感谢您的支持！', 1, 3, 1, '2026-01-20 10:00:00', '2026-01-25 11:13:53', '2026-01-25 11:13:53', 1);
INSERT INTO `system_notice` VALUES (2, '春节促销活动通知', '春节将至，平台推出新春促销活动！\n\n活动时间：2026年1月28日-2026年2月15日\n\n活动内容：\n1. 订单满100元减20元\n2. 新用户首单立减30元\n3. 推荐好友奖励50元\n\n请各位商户做好备货准备，预祝生意兴隆！', 2, 1, 1, '2026-01-18 14:00:00', '2026-01-25 11:13:53', '2026-01-25 11:13:53', 1);
INSERT INTO `system_notice` VALUES (3, '商户入驻规范更新', '各位商户：\n\n为了提升平台服务质量，现对商户入驻规范进行更新：\n\n1. 营业执照必须真实有效\n2. 食品经营许可证必须在有效期内\n3. 店铺照片不得少于3张\n4. 菜品图片必须真实清晰\n\n请各位商户及时完善相关信息。', 1, 1, 1, '2026-01-15 09:00:00', '2026-01-25 11:13:53', '2026-01-25 11:13:53', 1);
INSERT INTO `system_notice` VALUES (4, '平台抽成比例调整通知', '各位商户：\n\n经平台研究决定，自2026年2月1日起，平台抽成比例统一调整为12%。\n\n感谢您的理解与支持！', 1, 1, 1, '2026-01-10 16:00:00', '2026-01-25 11:13:53', '2026-01-25 11:13:53', 1);
INSERT INTO `system_notice` VALUES (5, '端午节活动预告', '端午节即将来临，平台将推出端午特惠活动！\n\n活动时间：2026年6月1日-2026年6月10日\n\n详情请关注后续通知。', 2, 3, 1, '2026-01-05 11:00:00', '2026-01-25 11:13:53', '2026-01-25 11:13:53', 1);
INSERT INTO `system_notice` VALUES (6, '平台使用指南', '欢迎使用吃货联盟外卖平台！\n\n本平台为您提供：\n1. 丰富的美食选择\n2. 快速的配送服务\n3. 优质的售后保障\n\n使用过程中如有任何问题，请联系客服：400-123-4567', 1, 2, 1, '2026-01-22 10:00:00', '2026-01-25 11:32:03', '2026-01-25 11:32:03', 1);
INSERT INTO `system_notice` VALUES (7, '新用户专属优惠', '新用户福利来啦！\n\n首单立减30元！\n满100元再减20元！\n\n优惠码：NEW2026\n有效期至：2026年2月28日\n\n赶快下单吧！', 2, 2, 1, '2026-01-20 14:00:00', '2026-01-25 11:32:03', '2026-01-25 11:32:03', 1);
INSERT INTO `system_notice` VALUES (8, '配送时间调整通知', '尊敬的用户：\n\n由于春节临近，部分商户配送时间将有所调整。\n\n预计配送时间：60-90分钟\n\n请您耐心等待，感谢理解！', 1, 3, 1, '2026-01-18 09:00:00', '2026-01-25 11:32:03', '2026-01-25 11:32:03', 1);
INSERT INTO `system_notice` VALUES (9, '积分商城上线啦', '好消息！积分商城正式上线！\n\n每次消费可获得积分\n积分可兑换：\n1. 优惠券\n2. 免配送费券\n3. 精美礼品\n\n快来看看吧！', 2, 2, 1, '2026-01-15 16:00:00', '2026-01-25 11:32:03', '2026-01-25 11:32:03', 1);
INSERT INTO `system_notice` VALUES (10, '春节配送安排通知', '亲爱的用户：\n\n春节期间（2月9日-2月15日）配送服务正常运营。\n\n部分商户可能会休息，请提前查看商户营业时间。\n\n祝您新春快乐！', 1, 3, 1, '2026-01-12 11:00:00', '2026-01-25 11:32:03', '2026-01-25 11:32:03', 1);
INSERT INTO `system_notice` VALUES (11, '推荐有奖活动', '邀请好友，双方都有奖！\n\n邀请1位好友注册并下单，双方各得50元优惠券\n邀请越多，奖励越多，上不封顶！\n\n活动时间：长期有效', 2, 2, 1, '2026-01-08 15:00:00', '2026-01-25 11:32:03', '2026-01-25 11:32:03', 1);
