  `rejection_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '拒单原因',
  `cancel_time` datetime NULL DEFAULT NULL COMMENT '取消时间',
