-- Table structure for platform_commission
-- ----------------------------
DROP TABLE IF EXISTS `platform_commission`;
CREATE TABLE `platform_commission`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `config_type` tinyint NOT NULL DEFAULT 1 COMMENT '配置类型 1全局默认 2商户特定 3分类特定',
  `merchant_id` bigint NULL DEFAULT NULL COMMENT '商户ID',
  `category_id` bigint NULL DEFAULT NULL COMMENT '分类ID',
  `commission_rate` decimal(5, 2) NOT NULL DEFAULT 15.00 COMMENT '抽成比例',
  `effective_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '生效时间',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '失效时间',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态 1启用 0禁用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_user` bigint NULL DEFAULT NULL COMMENT '创建人ID',
  `update_user` bigint NULL DEFAULT NULL COMMENT '更新人ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_merchant_id`(`merchant_id` ASC) USING BTREE,
  INDEX `idx_config_type`(`config_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '平台抽成配置表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of platform_commission
-- ----------------------------

