-- ----------------------------
-- View structure for v_merchant_order_stats
-- ----------------------------
DROP VIEW IF EXISTS `v_merchant_order_stats`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_merchant_order_stats` AS select `m`.`id` AS `merchant_id`,`m`.`merchant_name` AS `merchant_name`,count(`o`.`id`) AS `total_orders`,sum((case when (`o`.`status` = 5) then 1 else 0 end)) AS `completed_orders`,sum((case when (`o`.`pay_status` = 1) then `o`.`total_amount` else 0 end)) AS `total_revenue`,sum((case when (`o`.`pay_status` = 1) then `o`.`merchant_amount` else 0 end)) AS `merchant_revenue` from (`merchant` `m` left join `orders` `o` on((`m`.`id` = `o`.`merchant_id`))) group by `m`.`id`,`m`.`merchant_name`;

-- ----------------------------
-- Procedure structure for sp_clear_cart_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_clear_cart_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_clear_cart_by_batch`(IN p_user_batch_no VARCHAR(32))
BEGIN
    DECLARE v_batch_user_code VARCHAR(32);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_user_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_user_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '用户批次号不能为空';
    END IF;

    SET v_batch_user_code = UPPER(REPLACE(TRIM(p_user_batch_no), '-', ''));

    START TRANSACTION;

    DELETE sc
    FROM shopping_cart sc
    JOIN `user` u ON u.id = sc.user_id
    WHERE LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_batch_user_code)))
          = CAST(CONCAT('UB', v_batch_user_code) AS BINARY);

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_clear_menu_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_clear_menu_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_clear_menu_by_batch`(IN p_batch_no VARCHAR(32))
BEGIN
    DECLARE v_batch_code VARCHAR(32);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_batch_no IS NULL OR TRIM(p_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '批次号不能为空';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_batch_no), '-', ''));

    START TRANSACTION;

    DELETE sd
    FROM setmeal_dish sd
    JOIN setmeal s ON s.id = sd.setmeal_id
    JOIN merchant m ON m.id = s.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    DELETE s
    FROM setmeal s
    JOIN merchant m ON m.id = s.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    DELETE df
    FROM dish_flavor df
    JOIN dish d ON d.id = df.dish_id
    JOIN merchant m ON m.id = d.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    DELETE d
    FROM dish d
    JOIN merchant m ON m.id = d.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    DELETE c
    FROM category c
    JOIN merchant m ON m.id = c.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_clear_multi_cycle_settlement_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_clear_multi_cycle_settlement_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_clear_multi_cycle_settlement_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_begin_cycle VARCHAR(16),
    IN p_end_cycle VARCHAR(16))
BEGIN
    DECLARE v_batch_code VARCHAR(32);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_merchant_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));

    START TRANSACTION;

    DELETE ms
    FROM merchant_settlement ms
    JOIN merchant m ON m.id = ms.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY)
      AND (p_begin_cycle IS NULL OR CHAR_LENGTH(TRIM(p_begin_cycle)) = 0 OR CAST(ms.settlement_cycle AS BINARY) >= CAST(TRIM(p_begin_cycle) AS BINARY))
      AND (p_end_cycle IS NULL OR CHAR_LENGTH(TRIM(p_end_cycle)) = 0 OR CAST(ms.settlement_cycle AS BINARY) <= CAST(TRIM(p_end_cycle) AS BINARY));

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_clear_platform_commission_mock
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_clear_platform_commission_mock`;
delimiter ;;
CREATE PROCEDURE `sp_clear_platform_commission_mock`(IN p_merchant_batch_no VARCHAR(32))
BEGIN
    DECLARE v_batch_code VARCHAR(32);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_merchant_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));

    START TRANSACTION;

    DELETE FROM platform_commission
    WHERE config_type = 1
       OR (config_type = 3 AND category_id IN (1,2,3,4))
       OR (config_type = 2 AND merchant_id IN (
            SELECT id FROM (
                SELECT m.id
                FROM merchant m
                WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
                      = CAST(v_batch_code AS BINARY)
            ) x
       ));

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_clear_settlement_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_clear_settlement_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_clear_settlement_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_settlement_cycle VARCHAR(16))
BEGIN
    DECLARE v_batch_merchant_code VARCHAR(32);
    DECLARE v_cycle VARCHAR(16);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_merchant_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    SET v_batch_merchant_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_cycle = TRIM(IFNULL(p_settlement_cycle, ''));

    START TRANSACTION;

    DELETE ms
    FROM merchant_settlement ms
    JOIN merchant m ON m.id = ms.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_merchant_code))
          = CAST(v_batch_merchant_code AS BINARY)
      AND (CHAR_LENGTH(v_cycle) = 0 OR CAST(ms.settlement_cycle AS BINARY) = CAST(v_cycle AS BINARY));

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_clear_user_order_data_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_clear_user_order_data_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_clear_user_order_data_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_user_batch_no VARCHAR(32))
BEGIN
    DECLARE v_merchant_batch_code VARCHAR(32);
    DECLARE v_user_batch_code VARCHAR(32);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR TRIM(p_merchant_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    IF p_user_batch_no IS NULL OR TRIM(p_user_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '用户批次号不能为空';
    END IF;

    SET v_merchant_batch_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_user_batch_code = UPPER(REPLACE(TRIM(p_user_batch_no), '-', ''));

    START TRANSACTION;

    DELETE sc
    FROM shopping_cart sc
    JOIN `user` u ON u.id = sc.user_id
    WHERE LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
          = CAST(CONCAT('UB', v_user_batch_code) AS BINARY);

    DELETE r
    FROM order_review r
    JOIN orders o ON o.id = r.order_id
    JOIN merchant m ON m.id = o.merchant_id
    JOIN `user` u ON u.id = o.user_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_merchant_batch_code))
          = CAST(v_merchant_batch_code AS BINARY)
      AND LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
          = CAST(CONCAT('UB', v_user_batch_code) AS BINARY);

    DELETE od
    FROM order_detail od
    JOIN orders o ON o.id = od.order_id
    JOIN merchant m ON m.id = o.merchant_id
    JOIN `user` u ON u.id = o.user_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_merchant_batch_code))
          = CAST(v_merchant_batch_code AS BINARY)
      AND LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
          = CAST(CONCAT('UB', v_user_batch_code) AS BINARY);

    DELETE o
    FROM orders o
    JOIN merchant m ON m.id = o.merchant_id
    JOIN `user` u ON u.id = o.user_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_merchant_batch_code))
          = CAST(v_merchant_batch_code AS BINARY)
      AND LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
          = CAST(CONCAT('UB', v_user_batch_code) AS BINARY);

    DELETE a
    FROM address_book a
    JOIN `user` u ON u.id = a.user_id
    WHERE LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
          = CAST(CONCAT('UB', v_user_batch_code) AS BINARY);

    DELETE FROM `user`
    WHERE LEFT(CAST(openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
          = CAST(CONCAT('UB', v_user_batch_code) AS BINARY);

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_cart_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_cart_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_mock_cart_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_user_batch_no VARCHAR(32),
    IN p_cart_user_count INT,
    IN p_max_items_per_merchant INT)
BEGIN
    DECLARE v_done INT DEFAULT 0;
    DECLARE v_user_id BIGINT;
    DECLARE v_batch_user_code VARCHAR(32);
    DECLARE v_batch_merchant_code VARCHAR(32);
    DECLARE v_now DATETIME;
    DECLARE v_selected_users INT DEFAULT 0;
    DECLARE v_merchant_loop INT DEFAULT 1;
    DECLARE v_merchant_pick_count INT DEFAULT 0;
    DECLARE v_item_loop INT DEFAULT 1;
    DECLARE v_item_count INT DEFAULT 0;
    DECLARE v_merchant_id BIGINT;
    DECLARE v_has_dish INT DEFAULT 0;
    DECLARE v_has_setmeal INT DEFAULT 0;
    DECLARE v_dish_id BIGINT;
    DECLARE v_setmeal_id BIGINT;
    DECLARE v_name VARCHAR(128);
    DECLARE v_image VARCHAR(255);
    DECLARE v_flavor VARCHAR(255);
    DECLARE v_amount DECIMAL(10,2);
    DECLARE v_number INT DEFAULT 1;

    DECLARE cur_user CURSOR FOR
        SELECT u.id
        FROM `user` u
        WHERE LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_batch_user_code)))
              = CAST(CONCAT('UB', v_batch_user_code) AS BINARY)
        ORDER BY RAND();

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_merchant_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    IF p_user_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_user_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '用户批次号不能为空';
    END IF;

    IF p_cart_user_count IS NULL OR p_cart_user_count <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '购物车用户数必须大于 0';
    END IF;

    IF p_max_items_per_merchant IS NULL OR p_max_items_per_merchant <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '每商户购物车商品上限必须大于 0';
    END IF;

    SET v_batch_user_code = UPPER(REPLACE(TRIM(p_user_batch_no), '-', ''));
    SET v_batch_merchant_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_now = NOW();

    IF NOT EXISTS (
        SELECT 1 FROM `user` u
        WHERE LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_batch_user_code)))
              = CAST(CONCAT('UB', v_batch_user_code) AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '未找到对应用户批次';
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM merchant m
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_merchant_code))
              = CAST(v_batch_merchant_code AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '未找到对应商户批次';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM shopping_cart sc
        JOIN `user` u ON u.id = sc.user_id
        WHERE LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_batch_user_code)))
              = CAST(CONCAT('UB', v_batch_user_code) AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前用户批次已存在购物车数据，请先清理';
    END IF;

    START TRANSACTION;

    OPEN cur_user;

    user_loop: LOOP
        FETCH cur_user INTO v_user_id;
        IF v_done = 1 OR v_selected_users >= p_cart_user_count THEN
            LEAVE user_loop;
        END IF;

        SET v_merchant_pick_count = 1 + FLOOR(RAND() * 3);
        SET v_merchant_loop = 1;

        WHILE v_merchant_loop <= v_merchant_pick_count DO
            SELECT MAX(t.id)
            INTO v_merchant_id
            FROM (
                SELECT m.id
                FROM merchant m
                WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_merchant_code))
                      = CAST(v_batch_merchant_code AS BINARY)
                  AND m.audit_status = 1
                  AND m.status IN (1, 2)
                  AND m.id NOT IN (
                      SELECT sc.merchant_id
                      FROM shopping_cart sc
                      WHERE sc.user_id = v_user_id
                  )
                ORDER BY RAND()
                LIMIT 1
            ) t;

            IF v_merchant_id IS NULL THEN
                SET v_merchant_loop = v_merchant_pick_count + 1;
            ELSE
                SELECT COUNT(*) INTO v_has_dish
                FROM dish d
                WHERE d.merchant_id = v_merchant_id AND d.status = 1;

                SELECT COUNT(*) INTO v_has_setmeal
                FROM setmeal s
                WHERE s.merchant_id = v_merchant_id AND s.status = 1;

                SET v_item_count = 1 + FLOOR(RAND() * p_max_items_per_merchant);
                SET v_item_loop = 1;

                WHILE v_item_loop <= v_item_count DO
                    SET v_dish_id = NULL;
                    SET v_setmeal_id = NULL;
                    SET v_flavor = NULL;
                    SET v_number = 1 + FLOOR(RAND() * 3);

                    IF v_has_setmeal > 0 AND (v_has_dish = 0 OR RAND() < 0.30) THEN
                        SELECT
                            MAX(t.id),
                            MAX(t.name),
                            MAX(t.image),
                            MAX(t.price)
                        INTO v_setmeal_id, v_name, v_image, v_amount
                        FROM (
                            SELECT s.id, s.name, s.image, s.price
                            FROM setmeal s
                            WHERE s.merchant_id = v_merchant_id
                              AND s.status = 1
                              AND s.id NOT IN (
                                  SELECT IFNULL(sc.setmeal_id, -1)
                                  FROM shopping_cart sc
                                  WHERE sc.user_id = v_user_id
                                    AND sc.merchant_id = v_merchant_id
                              )
                            ORDER BY RAND()
                            LIMIT 1
                        ) t;
                    ELSE
                        SELECT
                            MAX(t.id),
                            MAX(t.name),
                            MAX(t.image),
                            MAX(t.price)
                        INTO v_dish_id, v_name, v_image, v_amount
                        FROM (
                            SELECT d.id, d.name, d.image, d.price
                            FROM dish d
                            WHERE d.merchant_id = v_merchant_id
                              AND d.status = 1
                              AND d.id NOT IN (
                                  SELECT IFNULL(sc.dish_id, -1)
                                  FROM shopping_cart sc
                                  WHERE sc.user_id = v_user_id
                                    AND sc.merchant_id = v_merchant_id
                              )
                            ORDER BY RAND()
                            LIMIT 1
                        ) t;

                        IF v_dish_id IS NOT NULL THEN
                            SELECT MAX(t.value)
                            INTO v_flavor
                            FROM (
                                SELECT df.value
                                FROM dish_flavor df
                                WHERE df.dish_id = v_dish_id
                                ORDER BY RAND()
                                LIMIT 1
                            ) t;
                        END IF;
                    END IF;

                    IF v_dish_id IS NOT NULL OR v_setmeal_id IS NOT NULL THEN
                            user_id,
                            merchant_id,
                            dish_id,
                            setmeal_id,
                            name,
                            image,
                            dish_flavor,
                            number,
                            amount,
                            create_time
                        ) VALUES (
                            v_user_id,
                            v_merchant_id,
                            v_dish_id,
                            v_setmeal_id,
                            v_name,
                            v_image,
                            v_flavor,
                            v_number,
                            v_amount,
                            DATE_SUB(v_now, INTERVAL FLOOR(RAND() * 1440) MINUTE)
                        );
                    END IF;

                    SET v_item_loop = v_item_loop + 1;
                END WHILE;

                SET v_merchant_loop = v_merchant_loop + 1;
            END IF;
        END WHILE;

        SET v_selected_users = v_selected_users + 1;
    END LOOP;

    CLOSE cur_user;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_categories_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_categories_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_mock_categories_by_batch`(IN p_batch_no VARCHAR(32),
    IN p_create_user BIGINT)
BEGIN
    DECLARE v_done INT DEFAULT 0;
    DECLARE v_merchant_id BIGINT;
    DECLARE v_biz_category_id BIGINT;
    DECLARE v_operator_id BIGINT DEFAULT 1;
    DECLARE v_batch_code VARCHAR(32);
    DECLARE v_now DATETIME;
    DECLARE v_existing_count INT DEFAULT 0;

    DECLARE cur_merchant CURSOR FOR
        SELECT id, biz_category_id
        FROM merchant
        WHERE LEFT(CAST(merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
        ORDER BY id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_batch_no IS NULL OR TRIM(p_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '批次号不能为空';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_batch_no), '-', ''));
    SET v_operator_id = IFNULL(p_create_user, 1);
    SET v_now = NOW();

    IF NOT EXISTS (
        SELECT 1
        FROM merchant
        WHERE LEFT(CAST(merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '未找到对应批次商户，请先生成商户数据';
    END IF;

    SELECT COUNT(*) INTO v_existing_count
    FROM category c
    JOIN merchant m ON m.id = c.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    IF v_existing_count > 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前批次已存在分类数据，请先清理';
    END IF;

    START TRANSACTION;

    OPEN cur_merchant;

    read_loop: LOOP
        FETCH cur_merchant INTO v_merchant_id, v_biz_category_id;
        IF v_done = 1 THEN
            LEAVE read_loop;
        END IF;

        CASE v_biz_category_id
            WHEN 1 THEN
            WHEN 2 THEN
            WHEN 3 THEN
            ELSE
        END CASE;
    END LOOP;

    CLOSE cur_merchant;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_menu_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_menu_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_mock_menu_by_batch`(IN p_batch_no VARCHAR(32),
    IN p_create_user BIGINT,
    IN p_dish_per_merchant INT,
    IN p_setmeal_per_merchant INT)
BEGIN
    DECLARE v_done INT DEFAULT 0;
    DECLARE v_i INT;
    DECLARE v_j INT;
    DECLARE v_pick INT;
    DECLARE v_merchant_id BIGINT;
    DECLARE v_biz_category_id BIGINT;
    DECLARE v_category1_id BIGINT;
    DECLARE v_category2_id BIGINT;
    DECLARE v_category3_id BIGINT;
    DECLARE v_setmeal_category_id BIGINT;
    DECLARE v_target_category_id BIGINT;
    DECLARE v_dish_id BIGINT;
    DECLARE v_setmeal_id BIGINT;
    DECLARE v_operator_id BIGINT DEFAULT 1;
    DECLARE v_batch_code VARCHAR(32);
    DECLARE v_now DATETIME;
    DECLARE v_existing_dish_count INT DEFAULT 0;
    DECLARE v_existing_setmeal_count INT DEFAULT 0;
    DECLARE v_dish_name VARCHAR(64);
    DECLARE v_dish_desc VARCHAR(255);
    DECLARE v_dish_image VARCHAR(255);
    DECLARE v_dish_price DECIMAL(10,2);
    DECLARE v_setmeal_name VARCHAR(64);
    DECLARE v_setmeal_desc VARCHAR(255);
    DECLARE v_setmeal_image VARCHAR(255);
    DECLARE v_setmeal_price DECIMAL(10,2);
    DECLARE v_flavor_name1 VARCHAR(32);
    DECLARE v_flavor_value1 VARCHAR(255);
    DECLARE v_flavor_name2 VARCHAR(32);
    DECLARE v_flavor_value2 VARCHAR(255);
    DECLARE v_cnt_cat1 INT DEFAULT 0;
    DECLARE v_cnt_cat2 INT DEFAULT 0;
    DECLARE v_cnt_cat3 INT DEFAULT 0;
    DECLARE v_dish_count_each INT DEFAULT 0;
    DECLARE v_price_sum DECIMAL(10,2);

    DECLARE cur_merchant CURSOR FOR
        SELECT m.id, m.biz_category_id,
               MAX(CASE WHEN c.type = 1 AND c.sort = 1 THEN c.id END) AS category1_id,
               MAX(CASE WHEN c.type = 1 AND c.sort = 2 THEN c.id END) AS category2_id,
               MAX(CASE WHEN c.type = 1 AND c.sort = 3 THEN c.id END) AS category3_id,
               MAX(CASE WHEN c.type = 2 AND c.sort = 4 THEN c.id END) AS setmeal_category_id
        FROM merchant m
        LEFT JOIN category c ON c.merchant_id = m.id AND c.status = 1
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
        GROUP BY m.id, m.biz_category_id
        ORDER BY m.id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_batch_no IS NULL OR TRIM(p_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '批次号不能为空';
    END IF;

    IF p_dish_per_merchant IS NULL OR p_dish_per_merchant < 3 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '每商户菜品数不能小于 3';
    END IF;

    IF p_setmeal_per_merchant IS NULL OR p_setmeal_per_merchant < 1 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '每商户套餐数不能小于 1';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_batch_no), '-', ''));
    SET v_operator_id = IFNULL(p_create_user, 1);
    SET v_now = NOW();
    SET v_dish_image = 'https://dummyimage.com/300x300/f59e0b/ffffff&text=Dish';
    SET v_setmeal_image = 'https://dummyimage.com/300x300/10b981/ffffff&text=Setmeal';

    IF NOT EXISTS (
        SELECT 1
        FROM category c
        JOIN merchant m ON m.id = c.merchant_id
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前批次未生成分类数据，请先执行 sp_mock_categories_by_batch';
    END IF;

    SELECT COUNT(*) INTO v_existing_dish_count
    FROM dish d
    JOIN merchant m ON m.id = d.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    SELECT COUNT(*) INTO v_existing_setmeal_count
    FROM setmeal s
    JOIN merchant m ON m.id = s.merchant_id
    WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
          = CAST(v_batch_code AS BINARY);

    IF v_existing_dish_count > 0 OR v_existing_setmeal_count > 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前批次已存在菜单数据，请先清理';
    END IF;

    START TRANSACTION;

    OPEN cur_merchant;

    merchant_loop: LOOP
        FETCH cur_merchant INTO v_merchant_id, v_biz_category_id, v_category1_id, v_category2_id, v_category3_id, v_setmeal_category_id;
        IF v_done = 1 THEN
            LEAVE merchant_loop;
        END IF;

        IF v_category1_id IS NULL OR v_category2_id IS NULL OR v_category3_id IS NULL OR v_setmeal_category_id IS NULL THEN
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '分类数据不完整，无法生成菜单';
        END IF;

        SET v_cnt_cat1 = FLOOR(p_dish_per_merchant / 3);
        SET v_cnt_cat2 = FLOOR(p_dish_per_merchant / 3);
        SET v_cnt_cat3 = p_dish_per_merchant - v_cnt_cat1 - v_cnt_cat2;
        SET v_i = 1;

        WHILE v_i <= p_dish_per_merchant DO
            IF v_i <= v_cnt_cat1 THEN
                SET v_target_category_id = v_category1_id;
            ELSEIF v_i <= v_cnt_cat1 + v_cnt_cat2 THEN
                SET v_target_category_id = v_category2_id;
            ELSE
                SET v_target_category_id = v_category3_id;
            END IF;

            CASE v_biz_category_id
                WHEN 1 THEN
                    CASE MOD(v_i - 1, 6)
                        WHEN 0 THEN SET v_dish_name = CONCAT('招牌黄焖鸡', LPAD(v_i, 2, '0')), v_dish_desc = '鸡肉入味，下饭首选', v_dish_price = ROUND(16 + RAND() * 8, 2), v_flavor_name1 = '辣度', v_flavor_value1 = '["不辣","微辣","中辣","重辣"]', v_flavor_name2 = '加料', v_flavor_value2 = '["加蛋","加肠","加饭"]';
                        WHEN 1 THEN SET v_dish_name = CONCAT('香菇滑鸡饭', LPAD(v_i, 2, '0')), v_dish_desc = '米饭粒粒分明，口感稳定', v_dish_price = ROUND(14 + RAND() * 7, 2), v_flavor_name1 = '分量', v_flavor_value1 = '["标准","加量"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 2 THEN SET v_dish_name = CONCAT('老坛酸菜面', LPAD(v_i, 2, '0')), v_dish_desc = '酸爽开胃，汤底浓郁', v_dish_price = ROUND(13 + RAND() * 6, 2), v_flavor_name1 = '辣度', v_flavor_value1 = '["不辣","微辣","中辣"]', v_flavor_name2 = '加料', v_flavor_value2 = '["加蛋","加丸子"]';
                        WHEN 3 THEN SET v_dish_name = CONCAT('脆皮鸡排', LPAD(v_i, 2, '0')), v_dish_desc = '外酥里嫩，现炸现卖', v_dish_price = ROUND(10 + RAND() * 6, 2), v_flavor_name1 = '口味', v_flavor_value1 = '["原味","孜然","香辣"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 4 THEN SET v_dish_name = CONCAT('紫菜蛋花汤', LPAD(v_i, 2, '0')), v_dish_desc = '清爽解腻，适合配餐', v_dish_price = ROUND(6 + RAND() * 4, 2), v_flavor_name1 = NULL, v_flavor_value1 = NULL, v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        ELSE SET v_dish_name = CONCAT('可乐鸡翅', LPAD(v_i, 2, '0')), v_dish_desc = '甜咸平衡，适合大众口味', v_dish_price = ROUND(12 + RAND() * 8, 2), v_flavor_name1 = '份量', v_flavor_value1 = '["小份","大份"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                    END CASE;
                WHEN 2 THEN
                    CASE MOD(v_i - 1, 6)
                        WHEN 0 THEN SET v_dish_name = CONCAT('杨枝甘露', LPAD(v_i, 2, '0')), v_dish_desc = '果香浓郁，清爽不腻', v_dish_price = ROUND(15 + RAND() * 8, 2), v_flavor_name1 = '甜度', v_flavor_value1 = '["无糖","少糖","半糖","标准糖"]', v_flavor_name2 = '温度', v_flavor_value2 = '["去冰","少冰","常温"]';
                        WHEN 1 THEN SET v_dish_name = CONCAT('生椰拿铁', LPAD(v_i, 2, '0')), v_dish_desc = '咖啡香气明显，椰乳顺滑', v_dish_price = ROUND(16 + RAND() * 10, 2), v_flavor_name1 = '冰量', v_flavor_value1 = '["去冰","少冰","标准冰"]', v_flavor_name2 = '甜度', v_flavor_value2 = '["无糖","少糖","标准糖"]';
                        WHEN 2 THEN SET v_dish_name = CONCAT('爆浆蛋挞', LPAD(v_i, 2, '0')), v_dish_desc = '酥皮层次分明，奶香浓郁', v_dish_price = ROUND(8 + RAND() * 6, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["单只","双只","四只"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 3 THEN SET v_dish_name = CONCAT('芝士奶盖茶', LPAD(v_i, 2, '0')), v_dish_desc = '茶底清爽，奶盖绵密', v_dish_price = ROUND(14 + RAND() * 8, 2), v_flavor_name1 = '甜度', v_flavor_value1 = '["少糖","半糖","标准糖"]', v_flavor_name2 = '温度', v_flavor_value2 = '["去冰","少冰","热"]';
                        WHEN 4 THEN SET v_dish_name = CONCAT('提拉米苏杯', LPAD(v_i, 2, '0')), v_dish_desc = '口感丰富，适合下午茶', v_dish_price = ROUND(12 + RAND() * 8, 2), v_flavor_name1 = NULL, v_flavor_value1 = NULL, v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        ELSE SET v_dish_name = CONCAT('美式咖啡', LPAD(v_i, 2, '0')), v_dish_desc = '风味干净，提神清爽', v_dish_price = ROUND(10 + RAND() * 6, 2), v_flavor_name1 = '温度', v_flavor_value1 = '["冰","热"]', v_flavor_name2 = '规格', v_flavor_value2 = '["中杯","大杯"]';
                    END CASE;
                WHEN 3 THEN
                    CASE MOD(v_i - 1, 6)
                        WHEN 0 THEN SET v_dish_name = CONCAT('薯片组合', LPAD(v_i, 2, '0')), v_dish_desc = '多口味零食组合，适合囤货', v_dish_price = ROUND(12 + RAND() * 10, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["小份","中份","大份"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 1 THEN SET v_dish_name = CONCAT('可乐整箱', LPAD(v_i, 2, '0')), v_dish_desc = '家庭聚会常备饮品', v_dish_price = ROUND(18 + RAND() * 16, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["6罐装","12罐装"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 2 THEN SET v_dish_name = CONCAT('抽纸三包装', LPAD(v_i, 2, '0')), v_dish_desc = '日常消耗品，家庭必备', v_dish_price = ROUND(9 + RAND() * 8, 2), v_flavor_name1 = NULL, v_flavor_value1 = NULL, v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 3 THEN SET v_dish_name = CONCAT('矿泉水整提', LPAD(v_i, 2, '0')), v_dish_desc = '便捷取用，办公室常备', v_dish_price = ROUND(10 + RAND() * 8, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["12瓶","24瓶"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 4 THEN SET v_dish_name = CONCAT('洗衣液补充装', LPAD(v_i, 2, '0')), v_dish_desc = '日用清洁补货方便', v_dish_price = ROUND(20 + RAND() * 18, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["500g","1kg"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        ELSE SET v_dish_name = CONCAT('泡面组合', LPAD(v_i, 2, '0')), v_dish_desc = '夜宵常备，开箱即食', v_dish_price = ROUND(14 + RAND() * 12, 2), v_flavor_name1 = '口味', v_flavor_value1 = '["红烧","酸菜","藤椒"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                    END CASE;
                ELSE
                    CASE MOD(v_i - 1, 6)
                        WHEN 0 THEN SET v_dish_name = CONCAT('红富士苹果', LPAD(v_i, 2, '0')), v_dish_desc = '脆甜多汁，适合全家食用', v_dish_price = ROUND(8 + RAND() * 10, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["500g","1000g","1500g"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 1 THEN SET v_dish_name = CONCAT('海南香蕉', LPAD(v_i, 2, '0')), v_dish_desc = '成熟度适中，口感绵甜', v_dish_price = ROUND(6 + RAND() * 8, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["500g","1000g"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 2 THEN SET v_dish_name = CONCAT('嫩菠菜', LPAD(v_i, 2, '0')), v_dish_desc = '叶片鲜嫩，适合清炒打汤', v_dish_price = ROUND(5 + RAND() * 6, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["250g","500g","1000g"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 3 THEN SET v_dish_name = CONCAT('净菜沙拉包', LPAD(v_i, 2, '0')), v_dish_desc = '轻食净菜，开袋即用', v_dish_price = ROUND(10 + RAND() * 10, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["单人份","双人份"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        WHEN 4 THEN SET v_dish_name = CONCAT('圣女果', LPAD(v_i, 2, '0')), v_dish_desc = '酸甜均衡，适合即食', v_dish_price = ROUND(7 + RAND() * 8, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["250g","500g"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                        ELSE SET v_dish_name = CONCAT('西兰花', LPAD(v_i, 2, '0')), v_dish_desc = '新鲜采摘，适合蒸煮快炒', v_dish_price = ROUND(6 + RAND() * 7, 2), v_flavor_name1 = '规格', v_flavor_value1 = '["500g","1000g"]', v_flavor_name2 = NULL, v_flavor_value2 = NULL;
                    END CASE;
            END CASE;

                merchant_id, category_id, name, price, image, description, status,
                create_time, update_time, create_user, update_user
            ) VALUES (
                v_merchant_id, v_target_category_id, v_dish_name, v_dish_price, v_dish_image, v_dish_desc, 1,
                v_now, v_now, v_operator_id, v_operator_id
            );

            SET v_dish_id = LAST_INSERT_ID();

            IF v_flavor_name1 IS NOT NULL THEN
                VALUES (v_dish_id, v_flavor_name1, v_flavor_value1);
            END IF;

            IF v_flavor_name2 IS NOT NULL THEN
                VALUES (v_dish_id, v_flavor_name2, v_flavor_value2);
            END IF;

            SET v_i = v_i + 1;
        END WHILE;

        SET v_j = 1;
        WHILE v_j <= p_setmeal_per_merchant DO
            CASE v_biz_category_id
                WHEN 1 THEN
                    SET v_setmeal_name = CONCAT('工作日双拼套餐', LPAD(v_j, 2, '0'));
                    SET v_setmeal_desc = '主食搭配小吃饮品，适合午晚餐';
                WHEN 2 THEN
                    SET v_setmeal_name = CONCAT('双人下午茶套餐', LPAD(v_j, 2, '0'));
                    SET v_setmeal_desc = '饮品搭配甜点，适合社交分享';
                WHEN 3 THEN
                    SET v_setmeal_name = CONCAT('宅家囤货组合', LPAD(v_j, 2, '0'));
                    SET v_setmeal_desc = '高频消耗品打包更划算';
                ELSE
                    SET v_setmeal_name = CONCAT('家庭果蔬组合', LPAD(v_j, 2, '0'));
                    SET v_setmeal_desc = '适合两到三天家庭食材采购';
            END CASE;

            SELECT ROUND(SUM(price), 2) INTO v_price_sum
            FROM (
                SELECT price
                FROM dish
                WHERE merchant_id = v_merchant_id
                ORDER BY RAND()
                LIMIT 3
            ) t;

            SET v_setmeal_price = ROUND(v_price_sum * (0.85 + RAND() * 0.10), 2);

                merchant_id, category_id, name, price, image, description, status,
                create_time, update_time, create_user, update_user
            ) VALUES (
                v_merchant_id, v_setmeal_category_id, v_setmeal_name, v_setmeal_price, v_setmeal_image, v_setmeal_desc, 1,
                v_now, v_now, v_operator_id, v_operator_id
            );

            SET v_setmeal_id = LAST_INSERT_ID();

            SET v_pick = 1;
            WHILE v_pick <= 3 DO
                SELECT v_setmeal_id, d.id, d.name, d.price, 1 + FLOOR(RAND() * 2)
                FROM dish d
                WHERE d.merchant_id = v_merchant_id
                  AND d.id NOT IN (
                      SELECT sd.dish_id
                      FROM setmeal_dish sd
                      WHERE sd.setmeal_id = v_setmeal_id
                  )
                ORDER BY RAND()
                LIMIT 1;

                SET v_pick = v_pick + 1;
            END WHILE;

            SET v_j = v_j + 1;
        END WHILE;
    END LOOP;

    CLOSE cur_merchant;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_merchants_nearby
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_merchants_nearby`;
delimiter ;;
CREATE PROCEDURE `sp_mock_merchants_nearby`(IN p_center_lng DECIMAL(10,6),
    IN p_center_lat DECIMAL(10,6),
    IN p_radius_km DECIMAL(10,2),
    IN p_total INT,
    IN p_batch_no VARCHAR(32),
    IN p_create_user BIGINT)
BEGIN
    DECLARE v_i INT DEFAULT 1;
    DECLARE v_category_id INT;
    DECLARE v_status INT;
    DECLARE v_theta DOUBLE;
    DECLARE v_distance_km DOUBLE;
    DECLARE v_delta_lat DOUBLE;
    DECLARE v_delta_lng DOUBLE;
    DECLARE v_lng DECIMAL(10,6);
    DECLARE v_lat DECIMAL(10,6);
    DECLARE v_merchant_id BIGINT;
    DECLARE v_operator_id BIGINT DEFAULT 1;
    DECLARE v_batch_code VARCHAR(32);
    DECLARE v_admin_prefix VARCHAR(40);
    DECLARE v_merchant_name VARCHAR(64);
    DECLARE v_merchant_code VARCHAR(32);
    DECLARE v_business_license VARCHAR(18);
    DECLARE v_legal_person VARCHAR(32);
    DECLARE v_contact_name VARCHAR(32);
    DECLARE v_contact_phone VARCHAR(11);
    DECLARE v_description VARCHAR(255);
    DECLARE v_business_hours VARCHAR(32);
    DECLARE v_min_delivery_amount DECIMAL(10,2);
    DECLARE v_delivery_fee DECIMAL(10,2);
    DECLARE v_commission_rate DECIMAL(10,2);
    DECLARE v_username VARCHAR(64);
    DECLARE v_admin_name VARCHAR(32);
    DECLARE v_admin_phone VARCHAR(11);
    DECLARE v_id_card VARCHAR(18);
    DECLARE v_logo VARCHAR(255);
    DECLARE v_now DATETIME;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_center_lng IS NULL OR p_center_lat IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '中心经纬度不能为空';
    END IF;

    IF p_radius_km IS NULL OR p_radius_km <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '半径必须大于 0';
    END IF;

    IF p_total IS NULL OR p_total <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '生成数量必须大于 0';
    END IF;

    IF p_batch_no IS NULL OR TRIM(p_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '批次号不能为空';
    END IF;

    SET v_operator_id = IFNULL(p_create_user, 1);
    SET v_now = NOW();
    SET v_batch_code = UPPER(REPLACE(TRIM(p_batch_no), '-', ''));
    SET v_admin_prefix = CONCAT('tm', LOWER(REPLACE(TRIM(p_batch_no), '-', '')));
    SET v_logo = 'https://dummyimage.com/200x200/f5c200/ffffff&text=Foodie';
    SET v_commission_rate = 18.00;

    IF EXISTS (
        SELECT 1
        FROM merchant
        WHERE LEFT(CAST(merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前批次 merchant 数据已存在，请更换批次号或先清理';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM merchant_admin
        WHERE LEFT(CAST(username AS BINARY), CHAR_LENGTH(v_admin_prefix))
              = CAST(v_admin_prefix AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前批次 merchant_admin 数据已存在，请更换批次号或先清理';
    END IF;

    START TRANSACTION;

    WHILE v_i <= p_total DO
        SET v_category_id = MOD(v_i - 1, 4) + 1;
        SET v_status = IF(RAND() < 0.75, 1, 2);
        SET v_theta = RAND() * 2 * PI();
        SET v_distance_km = p_radius_km * SQRT(RAND());

        -- 近似换算：1 纬度约等于 111.32km，1 经度约等于 111.32 * cos(latitude) km
        SET v_delta_lat = (v_distance_km / 111.32) * SIN(v_theta);
        SET v_delta_lng = (v_distance_km / (111.32 * COS(RADIANS(p_center_lat)))) * COS(v_theta);
        SET v_lng = ROUND(p_center_lng + v_delta_lng, 6);
        SET v_lat = ROUND(p_center_lat + v_delta_lat, 6);

        SET v_merchant_code = CONCAT(v_batch_code, LPAD(v_i, 4, '0'));
        SET v_business_license = CONCAT('MOCK', UPPER(LEFT(MD5(CONCAT(v_batch_code, '-', v_i)), 14)));
        SET v_contact_phone = CONCAT('13', LPAD(MOD(CRC32(CONCAT(v_batch_code, '-phone-', v_i)), 1000000000), 9, '0'));
        SET v_id_card = CONCAT('320', LPAD(MOD(CRC32(CONCAT(v_batch_code, '-idcard-', v_i)), 1000000000000000), 15, '0'));
        SET v_username = CONCAT(v_admin_prefix, LPAD(v_i, 3, '0'));

        CASE v_category_id
            WHEN 1 THEN
                SET v_merchant_name = CONCAT('美食测试店', LPAD(v_i, 3, '0'));
                SET v_legal_person = CONCAT('美食法人', LPAD(v_i, 3, '0'));
                SET v_contact_name = CONCAT('美食店长', LPAD(v_i, 3, '0'));
                SET v_admin_name = CONCAT('美食管理员', LPAD(v_i, 3, '0'));
                SET v_description = '现炒快餐、盖浇饭、面食小炒';
                SET v_business_hours = '09:00-21:00';
                SET v_min_delivery_amount = ROUND(18 + RAND() * 12, 2);
                SET v_delivery_fee = ROUND(3 + RAND() * 4, 2);
            WHEN 2 THEN
                SET v_merchant_name = CONCAT('甜饮测试店', LPAD(v_i, 3, '0'));
                SET v_legal_person = CONCAT('甜饮法人', LPAD(v_i, 3, '0'));
                SET v_contact_name = CONCAT('甜饮店长', LPAD(v_i, 3, '0'));
                SET v_admin_name = CONCAT('甜饮管理员', LPAD(v_i, 3, '0'));
                SET v_description = '奶茶咖啡、甜品蛋糕、下午茶';
                SET v_business_hours = '10:00-22:00';
                SET v_min_delivery_amount = ROUND(15 + RAND() * 10, 2);
                SET v_delivery_fee = ROUND(2 + RAND() * 4, 2);
            WHEN 3 THEN
                SET v_merchant_name = CONCAT('便利测试店', LPAD(v_i, 3, '0'));
                SET v_legal_person = CONCAT('便利法人', LPAD(v_i, 3, '0'));
                SET v_contact_name = CONCAT('便利店长', LPAD(v_i, 3, '0'));
                SET v_admin_name = CONCAT('便利管理员', LPAD(v_i, 3, '0'));
                SET v_description = '日用百货、零食饮料、应急用品';
                SET v_business_hours = '08:00-23:00';
                SET v_min_delivery_amount = ROUND(20 + RAND() * 15, 2);
                SET v_delivery_fee = ROUND(3 + RAND() * 5, 2);
            ELSE
                SET v_merchant_name = CONCAT('果蔬测试店', LPAD(v_i, 3, '0'));
                SET v_legal_person = CONCAT('果蔬法人', LPAD(v_i, 3, '0'));
                SET v_contact_name = CONCAT('果蔬店长', LPAD(v_i, 3, '0'));
                SET v_admin_name = CONCAT('果蔬管理员', LPAD(v_i, 3, '0'));
                SET v_description = '时令水果、新鲜蔬菜、轻食食材';
                SET v_business_hours = '07:30-21:30';
                SET v_min_delivery_amount = ROUND(16 + RAND() * 12, 2);
                SET v_delivery_fee = ROUND(2 + RAND() * 4, 2);
        END CASE;

        SET v_admin_phone = v_contact_phone;

            merchant_name,
            merchant_code,
            business_license,
            legal_person,
            contact_name,
            contact_phone,
            province_code,
            province_name,
            city_code,
            city_name,
            district_code,
            district_name,
            address,
            longitude,
            latitude,
            logo,
            description,
            biz_category_id,
            business_hours,
            min_delivery_amount,
            delivery_fee,
            commission_rate,
            status,
            audit_status,
            audit_reason,
            create_time,
            update_time,
            create_user,
            update_user
        ) VALUES (
            v_merchant_name,
            v_merchant_code,
            v_business_license,
            v_legal_person,
            v_contact_name,
            v_contact_phone,
            '320000',
            '江苏省',
            '321000',
            '扬州市',
            '321003',
            '邗江区',
            CONCAT('测试地址-', v_batch_code, '-', LPAD(v_i, 3, '0'), '号'),
            v_lng,
            v_lat,
            v_logo,
            v_description,
            v_category_id,
            v_business_hours,
            v_min_delivery_amount,
            v_delivery_fee,
            v_commission_rate,
            v_status,
            1,
            '批量测试数据-自动通过',
            v_now,
            v_now,
            v_operator_id,
            v_operator_id
        );

        SET v_merchant_id = LAST_INSERT_ID();

            merchant_id,
            username,
            password,
            name,
            phone,
            id_card,
            role,
            status,
            create_time,
            update_time,
            create_user,
            update_user
        ) VALUES (
            v_merchant_id,
            v_username,
            'e10adc3949ba59abbe56e057f20f883e',
            v_admin_name,
            v_admin_phone,
            v_id_card,
            1,
            1,
            v_now,
            v_now,
            v_operator_id,
            v_operator_id
        );

        SET v_i = v_i + 1;
    END WHILE;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_multi_cycle_settlement_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_multi_cycle_settlement_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_mock_multi_cycle_settlement_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_end_cycle VARCHAR(16),
    IN p_cycle_count INT,
    IN p_create_user BIGINT)
BEGIN
    DECLARE v_done INT DEFAULT 0;
    DECLARE v_merchant_id BIGINT;
    DECLARE v_batch_code VARCHAR(32);
    DECLARE v_now DATETIME;
    DECLARE v_operator_id BIGINT DEFAULT 1;
    DECLARE v_end_month DATE;
    DECLARE v_cycle_index INT DEFAULT 0;
    DECLARE v_cycle_date DATE;
    DECLARE v_cycle_label VARCHAR(16);
    DECLARE v_settlement_status INT;
    DECLARE v_settlement_time DATETIME;
    DECLARE v_order_count INT DEFAULT 0;
    DECLARE v_total_amount DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_platform_commission DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_merchant_amount DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_settlement_amount DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_scale DECIMAL(10,2) DEFAULT 1.00;

    DECLARE cur_merchant CURSOR FOR
        SELECT m.id
        FROM merchant m
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
        ORDER BY m.id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_merchant_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    IF p_end_cycle IS NULL OR CHAR_LENGTH(TRIM(p_end_cycle)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '结束周期不能为空';
    END IF;

    IF p_cycle_count IS NULL OR p_cycle_count <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '周期数必须大于 0';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_operator_id = IFNULL(p_create_user, 1);
    SET v_now = NOW();
    SET v_end_month = STR_TO_DATE(CONCAT(TRIM(p_end_cycle), '-01'), '%Y-%m-%d');

    IF v_end_month IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '结束周期格式错误，应为 yyyy-MM';
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM merchant m
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '未找到对应商户批次';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM merchant_settlement ms
        JOIN merchant m ON m.id = ms.merchant_id
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
          AND CAST(ms.settlement_cycle AS BINARY) IN (
              SELECT CAST(DATE_FORMAT(DATE_SUB(v_end_month, INTERVAL seq.seq MONTH), '%Y-%m') AS BINARY)
              FROM (
                  SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL
                  SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL
                  SELECT 10 UNION ALL SELECT 11
              ) seq
              WHERE seq.seq < p_cycle_count
          )
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '目标周期内已存在结算单，请先清理';
    END IF;

    START TRANSACTION;

    OPEN cur_merchant;

    merchant_loop: LOOP
        FETCH cur_merchant INTO v_merchant_id;
        IF v_done = 1 THEN
            LEAVE merchant_loop;
        END IF;

        SET v_cycle_index = 0;
        WHILE v_cycle_index < p_cycle_count DO
            SET v_cycle_date = DATE_SUB(v_end_month, INTERVAL v_cycle_index MONTH);
            SET v_cycle_label = DATE_FORMAT(v_cycle_date, '%Y-%m');

            SELECT COUNT(*),
                   IFNULL(SUM(o.total_amount), 0),
                   IFNULL(SUM(o.platform_commission), 0),
                   IFNULL(SUM(o.merchant_amount), 0)
            INTO v_order_count, v_total_amount, v_platform_commission, v_merchant_amount
            FROM orders o
            WHERE o.merchant_id = v_merchant_id
              AND o.status = 5
              AND o.pay_status = 1;

            IF v_order_count > 0 THEN
                IF v_cycle_index = 0 THEN
                    SET v_scale = 1.00;
                ELSEIF v_cycle_index = 1 THEN
                    SET v_scale = 0.88;
                ELSEIF v_cycle_index = 2 THEN
                    SET v_scale = 0.76;
                ELSE
                    SET v_scale = 0.65;
                END IF;

                SET v_order_count = GREATEST(1, FLOOR(v_order_count / p_cycle_count * (0.8 + RAND() * 0.6)));
                SET v_total_amount = ROUND(v_total_amount / p_cycle_count * v_scale * (0.9 + RAND() * 0.2), 2);
                SET v_platform_commission = ROUND(v_platform_commission / p_cycle_count * v_scale * (0.9 + RAND() * 0.2), 2);
                SET v_merchant_amount = ROUND(v_merchant_amount / p_cycle_count * v_scale * (0.9 + RAND() * 0.2), 2);
                SET v_settlement_amount = v_merchant_amount;

                IF v_cycle_index = 0 THEN
                    SET v_settlement_status = 1;
                    SET v_settlement_time = NULL;
                ELSE
                    IF RAND() < 0.85 THEN
                        SET v_settlement_status = 2;
                        SET v_settlement_time = DATE_ADD(LAST_DAY(v_cycle_date), INTERVAL (1 + FLOOR(RAND() * 5)) DAY);
                    ELSE
                        SET v_settlement_status = 3;
                        SET v_settlement_time = NULL;
                    END IF;
                END IF;

                    merchant_id,
                    settlement_cycle,
                    order_count,
                    total_amount,
                    platform_commission,
                    merchant_amount,
                    settlement_amount,
                    status,
                    settlement_time,
                    remark,
                    create_time,
                    update_time
                ) VALUES (
                    v_merchant_id,
                    v_cycle_label,
                    v_order_count,
                    v_total_amount,
                    v_platform_commission,
                    v_merchant_amount,
                    v_settlement_amount,
                    v_settlement_status,
                    v_settlement_time,
                    CONCAT('批量生成-', v_cycle_label),
                    v_now,
                    v_now
                );
            END IF;

            SET v_cycle_index = v_cycle_index + 1;
        END WHILE;
    END LOOP;

    CLOSE cur_merchant;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_orders_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_orders_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_mock_orders_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_user_batch_no VARCHAR(32),
    IN p_order_count INT)
BEGIN
    DECLARE v_i INT DEFAULT 1;
    DECLARE v_item_index INT DEFAULT 1;
    DECLARE v_item_count INT DEFAULT 0;
    DECLARE v_qty INT DEFAULT 1;
    DECLARE v_merchant_batch_code VARCHAR(32);
    DECLARE v_user_batch_code VARCHAR(32);
    DECLARE v_order_prefix VARCHAR(24);
    DECLARE v_order_number VARCHAR(32);
    DECLARE v_order_id BIGINT;
    DECLARE v_user_id BIGINT;
    DECLARE v_user_nickname VARCHAR(64);
    DECLARE v_user_phone VARCHAR(16);
    DECLARE v_address_book_id BIGINT;
    DECLARE v_consignee VARCHAR(64);
    DECLARE v_full_address VARCHAR(255);
    DECLARE v_merchant_id BIGINT;
    DECLARE v_delivery_fee DECIMAL(10,2);
    DECLARE v_commission_rate DECIMAL(10,2);
    DECLARE v_item_dish_id BIGINT;
    DECLARE v_item_setmeal_id BIGINT;
    DECLARE v_item_name VARCHAR(128);
    DECLARE v_item_image VARCHAR(255);
    DECLARE v_item_flavor VARCHAR(255);
    DECLARE v_item_price DECIMAL(10,2);
    DECLARE v_amount DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_pack_amount DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_platform_commission DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_merchant_amount DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_total_amount DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_status_rand DOUBLE;
    DECLARE v_status INT;
    DECLARE v_pay_status INT;
    DECLARE v_pay_method INT;
    DECLARE v_order_time DATETIME;
    DECLARE v_checkout_time DATETIME;
    DECLARE v_estimated_delivery_time DATETIME;
    DECLARE v_delivery_time DATETIME;
    DECLARE v_cancel_time DATETIME;
    DECLARE v_cancel_reason VARCHAR(255);
    DECLARE v_has_dish INT DEFAULT 0;
    DECLARE v_has_setmeal INT DEFAULT 0;
    DECLARE v_now DATETIME;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR TRIM(p_merchant_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    IF p_user_batch_no IS NULL OR TRIM(p_user_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '用户批次号不能为空';
    END IF;

    IF p_order_count IS NULL OR p_order_count <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '订单数量必须大于 0';
    END IF;

    SET v_merchant_batch_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_user_batch_code = UPPER(REPLACE(TRIM(p_user_batch_no), '-', ''));
    SET v_order_prefix = CONCAT('OB', LEFT(v_merchant_batch_code, 8), LEFT(v_user_batch_code, 8));
    SET v_now = NOW();

    IF NOT EXISTS (
        SELECT 1 FROM merchant
        WHERE LEFT(CAST(merchant_code AS BINARY), CHAR_LENGTH(v_merchant_batch_code))
              = CAST(v_merchant_batch_code AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '未找到对应商户批次';
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM `user`
        WHERE LEFT(CAST(openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
              = CAST(CONCAT('UB', v_user_batch_code) AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '未找到对应用户批次';
    END IF;

    IF EXISTS (
        SELECT 1 FROM orders
        WHERE LEFT(CAST(order_number AS BINARY), CHAR_LENGTH(v_order_prefix))
              = CAST(v_order_prefix AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前订单批次已存在，请先清理';
    END IF;

    START TRANSACTION;

    WHILE v_i <= p_order_count DO
        SELECT u.id, u.nickname, u.phone
        INTO v_user_id, v_user_nickname, v_user_phone
        FROM `user` u
        WHERE LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
              = CAST(CONCAT('UB', v_user_batch_code) AS BINARY)
        ORDER BY RAND()
        LIMIT 1;

        SELECT a.id,
               a.consignee,
               CONCAT(a.province_name, a.city_name, a.district_name, a.detail)
        INTO v_address_book_id, v_consignee, v_full_address
        FROM address_book a
        WHERE a.user_id = v_user_id
        ORDER BY a.is_default DESC, RAND()
        LIMIT 1;

        SELECT m.id,
               m.delivery_fee,
               m.commission_rate
        INTO v_merchant_id, v_delivery_fee, v_commission_rate
        FROM merchant m
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_merchant_batch_code))
              = CAST(v_merchant_batch_code AS BINARY)
          AND m.audit_status = 1
          AND m.status IN (1, 2)
        ORDER BY RAND()
        LIMIT 1;

        SET v_order_number = CONCAT(v_order_prefix, LPAD(v_i, 6, '0'));
        SET v_order_time = DATE_SUB(v_now, INTERVAL FLOOR(RAND() * 43200) MINUTE);
        SET v_pay_method = IF(RAND() < 0.5, 1, 2);
        SET v_status_rand = RAND();
        SET v_checkout_time = NULL;
        SET v_estimated_delivery_time = NULL;
        SET v_delivery_time = NULL;
        SET v_cancel_time = NULL;
        SET v_cancel_reason = NULL;

        IF v_status_rand < 0.10 THEN
            SET v_status = 1;
            SET v_pay_status = 0;
        ELSEIF v_status_rand < 0.20 THEN
            SET v_status = 2;
            SET v_pay_status = 1;
            SET v_checkout_time = DATE_ADD(v_order_time, INTERVAL 5 MINUTE);
        ELSEIF v_status_rand < 0.30 THEN
            SET v_status = 3;
            SET v_pay_status = 1;
            SET v_checkout_time = DATE_ADD(v_order_time, INTERVAL 5 MINUTE);
            SET v_estimated_delivery_time = DATE_ADD(v_order_time, INTERVAL 45 MINUTE);
        ELSEIF v_status_rand < 0.40 THEN
            SET v_status = 4;
            SET v_pay_status = 1;
            SET v_checkout_time = DATE_ADD(v_order_time, INTERVAL 5 MINUTE);
            SET v_estimated_delivery_time = DATE_ADD(v_order_time, INTERVAL 45 MINUTE);
        ELSEIF v_status_rand < 0.95 THEN
            SET v_status = 5;
            SET v_pay_status = 1;
            SET v_checkout_time = DATE_ADD(v_order_time, INTERVAL 5 MINUTE);
            SET v_estimated_delivery_time = DATE_ADD(v_order_time, INTERVAL 45 MINUTE);
            SET v_delivery_time = DATE_ADD(v_order_time, INTERVAL (35 + FLOOR(RAND() * 30)) MINUTE);
        ELSE
            SET v_status = 6;
            SET v_pay_status = 1;
            SET v_checkout_time = DATE_ADD(v_order_time, INTERVAL 5 MINUTE);
            SET v_cancel_time = DATE_ADD(v_order_time, INTERVAL 12 MINUTE);
            SET v_cancel_reason = '用户临时取消';
        END IF;

            order_number,
            user_id,
            merchant_id,
            address_book_id,
            status,
            order_time,
            checkout_time,
            pay_method,
            pay_status,
            amount,
            delivery_fee,
            pack_amount,
            platform_commission,
            merchant_amount,
            total_amount,
            remark,
            phone,
            address,
            consignee,
            user_name,
            cancel_reason,
            rejection_reason,
            cancel_time,
            estimated_delivery_time,
            delivery_time,
            tableware_number,
            create_time,
            update_time
        ) VALUES (
            v_order_number,
            v_user_id,
            v_merchant_id,
            v_address_book_id,
            v_status,
            v_order_time,
            v_checkout_time,
            v_pay_method,
            v_pay_status,
            0,
            IFNULL(v_delivery_fee, 0),
            0,
            0,
            0,
            0,
            '批量测试订单',
            v_user_phone,
            v_full_address,
            v_consignee,
            v_consignee,
            v_cancel_reason,
            NULL,
            v_cancel_time,
            v_estimated_delivery_time,
            v_delivery_time,
            1 + FLOOR(RAND() * 3),
            v_order_time,
            v_order_time
        );

        SET v_order_id = LAST_INSERT_ID();
        SET v_item_count = 2 + FLOOR(RAND() * 4);
        SET v_item_index = 1;
        SET v_amount = 0.00;
        SET v_pack_amount = 0.00;

        SELECT COUNT(*) INTO v_has_dish
        FROM dish
        WHERE merchant_id = v_merchant_id AND status = 1;

        SELECT COUNT(*) INTO v_has_setmeal
        FROM setmeal
        WHERE merchant_id = v_merchant_id AND status = 1;

        WHILE v_item_index <= v_item_count DO
            SET v_qty = 1 + FLOOR(RAND() * 2);
            SET v_item_dish_id = NULL;
            SET v_item_setmeal_id = NULL;
            SET v_item_flavor = NULL;

            IF v_has_setmeal > 0 AND (v_has_dish = 0 OR RAND() < 0.25) THEN
                SELECT s.id, s.name, s.image, s.price
                INTO v_item_setmeal_id, v_item_name, v_item_image, v_item_price
                FROM setmeal s
                WHERE s.merchant_id = v_merchant_id AND s.status = 1
                ORDER BY RAND()
                LIMIT 1;
            ELSE
                SELECT d.id, d.name, d.image, d.price
                INTO v_item_dish_id, v_item_name, v_item_image, v_item_price
                FROM dish d
                WHERE d.merchant_id = v_merchant_id AND d.status = 1
                ORDER BY RAND()
                LIMIT 1;

                SET v_item_flavor = (
                    SELECT df.value
                    FROM dish_flavor df
                    WHERE df.dish_id = v_item_dish_id
                    ORDER BY RAND()
                    LIMIT 1
                );
            END IF;

                order_id,
                dish_id,
                setmeal_id,
                name,
                image,
                dish_flavor,
                number,
                amount
            ) VALUES (
                v_order_id,
                v_item_dish_id,
                v_item_setmeal_id,
                v_item_name,
                v_item_image,
                v_item_flavor,
                v_qty,
                v_item_price
            );

            SET v_amount = v_amount + (v_item_price * v_qty);
            SET v_pack_amount = v_pack_amount + 1.00;
            SET v_item_index = v_item_index + 1;
        END WHILE;

        SET v_platform_commission = ROUND(v_amount * IFNULL(v_commission_rate, 18.00) / 100, 2);
        SET v_merchant_amount = ROUND(v_amount - v_platform_commission, 2);
        SET v_total_amount = ROUND(v_amount + IFNULL(v_delivery_fee, 0) + v_pack_amount, 2);

        UPDATE orders
        SET amount = ROUND(v_amount, 2),
            delivery_fee = IFNULL(v_delivery_fee, 0),
            pack_amount = ROUND(v_pack_amount, 2),
            platform_commission = v_platform_commission,
            merchant_amount = v_merchant_amount,
            total_amount = v_total_amount,
            update_time = v_now
        WHERE id = v_order_id;

        SET v_i = v_i + 1;
    END WHILE;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_platform_commission_config
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_platform_commission_config`;
delimiter ;;
CREATE PROCEDURE `sp_mock_platform_commission_config`(IN p_merchant_batch_no VARCHAR(32),
    IN p_create_user BIGINT)
BEGIN
    DECLARE v_batch_code VARCHAR(32);
    DECLARE v_now DATETIME;
    DECLARE v_operator_id BIGINT DEFAULT 1;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_merchant_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_now = NOW();
    SET v_operator_id = IFNULL(p_create_user, 1);

    IF EXISTS (
        SELECT 1 FROM platform_commission pc
        WHERE (pc.config_type = 1)
           OR (pc.config_type = 2 AND pc.merchant_id IN (
                SELECT m.id FROM merchant m
                WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
                      = CAST(v_batch_code AS BINARY)
           ))
           OR (pc.config_type = 3 AND pc.category_id IN (1,2,3,4))
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '检测到已有抽成配置，请先清理后再生成';
    END IF;

    START TRANSACTION;

        config_type,
        merchant_id,
        category_id,
        commission_rate,
        effective_time,
        expire_time,
        status,
        create_time,
        update_time,
        create_user,
        update_user
    ) VALUES (
        1,
        NULL,
        NULL,
        18.00,
        v_now,
        NULL,
        1,
        v_now,
        v_now,
        v_operator_id,
        v_operator_id
    );

        config_type,
        merchant_id,
        category_id,
        commission_rate,
        effective_time,
        expire_time,
        status,
        create_time,
        update_time,
        create_user,
        update_user
    ) VALUES
    (3, NULL, 1, 16.00, v_now, NULL, 1, v_now, v_now, v_operator_id, v_operator_id),
    (3, NULL, 2, 19.00, v_now, NULL, 1, v_now, v_now, v_operator_id, v_operator_id),
    (3, NULL, 3, 12.00, v_now, NULL, 1, v_now, v_now, v_operator_id, v_operator_id),
    (3, NULL, 4, 10.00, v_now, NULL, 1, v_now, v_now, v_operator_id, v_operator_id);

        config_type,
        merchant_id,
        category_id,
        commission_rate,
        effective_time,
        expire_time,
        status,
        create_time,
        update_time,
        create_user,
        update_user
    )
    SELECT
        2,
        t.id,
        NULL,
        CASE MOD(t.id, 5)
            WHEN 0 THEN 11.50
            WHEN 1 THEN 13.00
            WHEN 2 THEN 14.50
            WHEN 3 THEN 15.50
            ELSE 17.00
        END,
        v_now,
        NULL,
        1,
        v_now,
        v_now,
        v_operator_id,
        v_operator_id
    FROM (
        SELECT m.id
        FROM merchant m
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_code))
              = CAST(v_batch_code AS BINARY)
        ORDER BY m.id
        LIMIT 12
    ) t;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_reviews_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_reviews_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_mock_reviews_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_user_batch_no VARCHAR(32),
    IN p_review_ratio DECIMAL(5,2))
BEGIN
    DECLARE v_done INT DEFAULT 0;
    DECLARE v_order_id BIGINT;
    DECLARE v_user_id BIGINT;
    DECLARE v_merchant_id BIGINT;
    DECLARE v_base_time DATETIME;
    DECLARE v_merchant_batch_code VARCHAR(32);
    DECLARE v_user_batch_code VARCHAR(32);
    DECLARE v_ratio DECIMAL(5,2);
    DECLARE v_rating INT;
    DECLARE v_content VARCHAR(255);
    DECLARE v_images VARCHAR(500);
    DECLARE v_reply VARCHAR(255);
    DECLARE v_reply_time DATETIME;
    DECLARE v_create_time DATETIME;
    DECLARE v_rand DOUBLE;

    DECLARE cur_review CURSOR FOR
        SELECT o.id,
               o.user_id,
               o.merchant_id,
               IFNULL(o.delivery_time, IFNULL(o.checkout_time, o.order_time)) AS base_time
        FROM orders o
        JOIN merchant m ON m.id = o.merchant_id
        JOIN `user` u ON u.id = o.user_id
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_merchant_batch_code))
              = CAST(v_merchant_batch_code AS BINARY)
          AND LEFT(CAST(u.openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_user_batch_code)))
              = CAST(CONCAT('UB', v_user_batch_code) AS BINARY)
          AND o.status = 5
          AND o.pay_status = 1
          AND NOT EXISTS (
              SELECT 1 FROM order_review r WHERE r.order_id = o.id
          )
        ORDER BY o.id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR TRIM(p_merchant_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    IF p_user_batch_no IS NULL OR TRIM(p_user_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '用户批次号不能为空';
    END IF;

    IF p_review_ratio IS NULL OR p_review_ratio <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '评价覆盖率必须大于 0';
    END IF;

    SET v_merchant_batch_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_user_batch_code = UPPER(REPLACE(TRIM(p_user_batch_no), '-', ''));
    SET v_ratio = IF(p_review_ratio > 1, p_review_ratio / 100, p_review_ratio);

    START TRANSACTION;

    OPEN cur_review;

    review_loop: LOOP
        FETCH cur_review INTO v_order_id, v_user_id, v_merchant_id, v_base_time;
        IF v_done = 1 THEN
            LEAVE review_loop;
        END IF;

        IF RAND() <= v_ratio THEN
            SET v_rand = RAND();

            IF v_rand < 0.35 THEN
                SET v_rating = 5;
                SET v_content = '配送及时，口味稳定，会继续回购';
            ELSEIF v_rand < 0.70 THEN
                SET v_rating = 4;
                SET v_content = '整体不错，分量合适，体验较好';
            ELSEIF v_rand < 0.85 THEN
                SET v_rating = 3;
                SET v_content = '中规中矩，口味正常，包装还可以';
            ELSEIF v_rand < 0.95 THEN
                SET v_rating = 2;
                SET v_content = '送达稍慢，口感一般，希望改进';
            ELSE
                SET v_rating = 1;
                SET v_content = '本次体验较差，和预期有差距';
            END IF;

            SET v_images = NULL;
            IF RAND() < 0.20 THEN
                SET v_images = 'https://dummyimage.com/300x300/f97316/ffffff&text=Review';
            END IF;

            SET v_reply = NULL;
            SET v_reply_time = NULL;
            IF RAND() < 0.30 THEN
                SET v_reply = '感谢反馈，我们会持续优化服务与口味';
                SET v_reply_time = DATE_ADD(v_base_time, INTERVAL (2 + FLOOR(RAND() * 48)) HOUR);
            END IF;

            SET v_create_time = DATE_ADD(v_base_time, INTERVAL (1 + FLOOR(RAND() * 72)) HOUR);

                order_id,
                user_id,
                merchant_id,
                rating,
                content,
                images,
                merchant_reply,
                reply_time,
                create_time,
                update_time
            ) VALUES (
                v_order_id,
                v_user_id,
                v_merchant_id,
                v_rating,
                v_content,
                v_images,
                v_reply,
                v_reply_time,
                v_create_time,
                v_create_time
            );
        END IF;
    END LOOP;

    CLOSE cur_review;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_settlement_by_batch
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_settlement_by_batch`;
delimiter ;;
CREATE PROCEDURE `sp_mock_settlement_by_batch`(IN p_merchant_batch_no VARCHAR(32),
    IN p_settlement_cycle VARCHAR(16),
    IN p_default_status INT)
BEGIN
    DECLARE v_done INT DEFAULT 0;
    DECLARE v_merchant_id BIGINT;
    DECLARE v_batch_merchant_code VARCHAR(32);
    DECLARE v_cycle VARCHAR(16);
    DECLARE v_begin_time DATETIME;
    DECLARE v_end_time DATETIME;
    DECLARE v_order_count INT DEFAULT 0;
    DECLARE v_total_amount DECIMAL(10,2);
    DECLARE v_platform_commission DECIMAL(10,2);
    DECLARE v_merchant_amount DECIMAL(10,2);
    DECLARE v_settlement_amount DECIMAL(10,2);
    DECLARE v_status INT DEFAULT 1;
    DECLARE v_settlement_time DATETIME;
    DECLARE v_remark VARCHAR(255);
    DECLARE v_now DATETIME;

    DECLARE cur_merchant CURSOR FOR
        SELECT m.id
        FROM merchant m
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_merchant_code))
              = CAST(v_batch_merchant_code AS BINARY)
        ORDER BY m.id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_merchant_batch_no IS NULL OR CHAR_LENGTH(TRIM(p_merchant_batch_no)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '商户批次号不能为空';
    END IF;

    IF p_settlement_cycle IS NULL OR CHAR_LENGTH(TRIM(p_settlement_cycle)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '结算周期不能为空';
    END IF;

    SET v_batch_merchant_code = UPPER(REPLACE(TRIM(p_merchant_batch_no), '-', ''));
    SET v_cycle = TRIM(p_settlement_cycle);
    SET v_now = NOW();
    SET v_status = IFNULL(p_default_status, 1);
    SET v_begin_time = STR_TO_DATE(CONCAT(v_cycle, '-01 00:00:00'), '%Y-%m-%d %H:%i:%s');
    SET v_end_time = DATE_SUB(DATE_ADD(LAST_DAY(v_begin_time), INTERVAL 1 DAY), INTERVAL 1 SECOND);

    IF NOT EXISTS (
        SELECT 1 FROM merchant m
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_merchant_code))
              = CAST(v_batch_merchant_code AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '未找到对应商户批次';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM merchant_settlement ms
        JOIN merchant m ON m.id = ms.merchant_id
        WHERE LEFT(CAST(m.merchant_code AS BINARY), CHAR_LENGTH(v_batch_merchant_code))
              = CAST(v_batch_merchant_code AS BINARY)
          AND CAST(ms.settlement_cycle AS BINARY) = CAST(v_cycle AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前周期结算单已存在，请先清理';
    END IF;

    START TRANSACTION;

    OPEN cur_merchant;

    merchant_loop: LOOP
        FETCH cur_merchant INTO v_merchant_id;
        IF v_done = 1 THEN
            LEAVE merchant_loop;
        END IF;

        SELECT COUNT(*),
               IFNULL(SUM(o.total_amount), 0),
               IFNULL(SUM(o.platform_commission), 0),
               IFNULL(SUM(o.merchant_amount), 0)
        INTO v_order_count, v_total_amount, v_platform_commission, v_merchant_amount
        FROM orders o
        WHERE o.merchant_id = v_merchant_id
          AND o.status = 5
          AND o.pay_status = 1
          AND o.order_time BETWEEN v_begin_time AND v_end_time;

        IF v_order_count > 0 THEN
            SET v_settlement_amount = v_merchant_amount;
            SET v_settlement_time = NULL;
            SET v_remark = NULL;

            IF v_status = 2 THEN
                SET v_settlement_time = DATE_ADD(v_end_time, INTERVAL (1 + FLOOR(RAND() * 5)) DAY);
                SET v_remark = '批量生成-已结算';
            ELSEIF v_status = 3 THEN
                SET v_settlement_time = NULL;
                SET v_remark = '批量生成-已取消';
            ELSE
                SET v_remark = '批量生成-待结算';
            END IF;

                merchant_id,
                settlement_cycle,
                order_count,
                total_amount,
                platform_commission,
                merchant_amount,
                settlement_amount,
                status,
                settlement_time,
                remark,
                create_time,
                update_time
            ) VALUES (
                v_merchant_id,
                v_cycle,
                v_order_count,
                ROUND(v_total_amount, 2),
                ROUND(v_platform_commission, 2),
                ROUND(v_merchant_amount, 2),
                ROUND(v_settlement_amount, 2),
                v_status,
                v_settlement_time,
                v_remark,
                v_now,
                v_now
            );
        END IF;
    END LOOP;

    CLOSE cur_merchant;

    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_mock_users_and_addresses
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_mock_users_and_addresses`;
delimiter ;;
CREATE PROCEDURE `sp_mock_users_and_addresses`(IN p_user_batch_no VARCHAR(32),
    IN p_user_count INT,
    IN p_address_per_user INT,
    IN p_center_lng DECIMAL(10,6),
    IN p_center_lat DECIMAL(10,6))
BEGIN
    DECLARE v_i INT DEFAULT 1;
    DECLARE v_j INT DEFAULT 1;
    DECLARE v_user_id BIGINT;
    DECLARE v_batch_code VARCHAR(32);
    DECLARE v_openid VARCHAR(64);
    DECLARE v_phone VARCHAR(11);
    DECLARE v_nickname VARCHAR(32);
    DECLARE v_avatar VARCHAR(255);
    DECLARE v_sex INT;
    DECLARE v_birthday DATE;
    DECLARE v_theta DOUBLE;
    DECLARE v_distance_km DOUBLE;
    DECLARE v_delta_lat DOUBLE;
    DECLARE v_delta_lng DOUBLE;
    DECLARE v_lng DECIMAL(10,6);
    DECLARE v_lat DECIMAL(10,6);
    DECLARE v_label VARCHAR(16);
    DECLARE v_detail VARCHAR(128);
    DECLARE v_consignee VARCHAR(32);
    DECLARE v_now DATETIME;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_user_batch_no IS NULL OR TRIM(p_user_batch_no) = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '用户批次号不能为空';
    END IF;

    IF p_user_count IS NULL OR p_user_count <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '用户数量必须大于 0';
    END IF;

    IF p_address_per_user IS NULL OR p_address_per_user <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '每用户地址数必须大于 0';
    END IF;

    SET v_batch_code = UPPER(REPLACE(TRIM(p_user_batch_no), '-', ''));
    SET v_now = NOW();
    SET v_avatar = 'https://dummyimage.com/200x200/60a5fa/ffffff&text=User';

    IF EXISTS (
        SELECT 1
        FROM `user`
        WHERE LEFT(CAST(openid AS BINARY), CHAR_LENGTH(CONCAT('UB', v_batch_code)))
              = CAST(CONCAT('UB', v_batch_code) AS BINARY)
    ) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = '当前用户批次已存在，请更换批次号或先清理';
    END IF;

    START TRANSACTION;

    WHILE v_i <= p_user_count DO
        SET v_openid = CONCAT('UB', v_batch_code, LPAD(v_i, 4, '0'));
        SET v_phone = CONCAT('15', LPAD(MOD(CRC32(CONCAT(v_batch_code, '-phone-', v_i)), 1000000000), 9, '0'));
        SET v_nickname = CONCAT('测试用户', LPAD(v_i, 3, '0'));
        SET v_sex = IF(RAND() < 0.5, 1, 2);
        SET v_birthday = DATE_SUB(CURDATE(), INTERVAL (18 + FLOOR(RAND() * 22)) * 365 DAY);

            openid,
            phone,
            password,
            nickname,
            avatar,
            sex,
            birthday,
            status,
            create_time,
            update_time,
            has_phone,
            has_password,
            has_wechat
        ) VALUES (
            v_openid,
            v_phone,
            'e10adc3949ba59abbe56e057f20f883e',
            v_nickname,
            v_avatar,
            v_sex,
            v_birthday,
            1,
            v_now,
            v_now,
            1,
            1,
            0
        );

        SET v_user_id = LAST_INSERT_ID();
        SET v_consignee = CONCAT('收货人', LPAD(v_i, 3, '0'));
        SET v_j = 1;

        WHILE v_j <= p_address_per_user DO
            SET v_theta = RAND() * 2 * PI();
            SET v_distance_km = 1 + RAND() * 7;
            SET v_delta_lat = (v_distance_km / 111.32) * SIN(v_theta);
            SET v_delta_lng = (v_distance_km / (111.32 * COS(RADIANS(p_center_lat)))) * COS(v_theta);
            SET v_lng = ROUND(p_center_lng + v_delta_lng, 6);
            SET v_lat = ROUND(p_center_lat + v_delta_lat, 6);
            SET v_label = CASE MOD(v_j, 3)
                WHEN 1 THEN '家'
                WHEN 2 THEN '公司'
                ELSE '学校'
            END;
            SET v_detail = CONCAT('测试地址-', v_batch_code, '-', LPAD(v_i, 3, '0'), '-', LPAD(v_j, 2, '0'), '号');

                user_id,
                consignee,
                sex,
                phone,
                province_code,
                province_name,
                city_code,
                city_name,
                district_code,
                district_name,
                detail,
                label,
                longitude,
                latitude,
                is_default,
                create_time,
                update_time
            ) VALUES (
                v_user_id,
                v_consignee,
                v_sex,
                v_phone,
                '320000',
                '江苏省',
                '321000',
                '扬州市',
                '321003',
                '邗江区',
                v_detail,
                v_label,
                v_lng,
                v_lat,
                IF(v_j = 1, 1, 0),
                v_now,
                v_now
            );

            SET v_j = v_j + 1;
        END WHILE;

        SET v_i = v_i + 1;
    END WHILE;

    COMMIT;
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
